window.__QUIZ_DATA__=[{"id":"objective>Biology>2002>1","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"which of the following characteristics differentiates a palisade cell from a liver cell? the possession of","images":[],"options":{"A":"a cell wall and cytoplasm","B":"a vacuole and a nucleus","C":"non-cell membrane and chloroplast","D":"a cell wall and chloroplast"},"answer":"D","explanation":"Palisade cells are found in the mesophyll of a leaf and their main function is the photosynthesis. They are different from liver cells because they have a cell wall and chloroplasts. The cell wall provides structural support and the chloroplast is where photosynthesis occurs. Liver cells, being animal cells, do not have these structures. Therefore, the possession of a cell wall and chloroplast differentiates a palisade cell from a liver cell.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>2","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Which of the following organism has both plant and animals-like features?","images":[],"options":{"A":"paramecium","B":"euglena","C":"amoeba","D":"spirogyra"},"answer":"B","explanation":"Euglena is a single-celled organism that exhibits features of both plants and animals. Like plants, it has chloroplasts and can perform photosynthesis, and like animals, it can move around and consume food when light is not available for photosynthesis.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>3","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which part of a plant cell contains celluose?","images":[],"options":{"A":"vacuole","B":"ctoplasm","C":"cell wall","D":"choroplast"},"answer":"C","explanation":"The cell wall of a plant cell contains cellulose. Cellulose is a complex carbohydrate, or polysaccharide, that provides structural support to the cell. It is the main component of the cell wall in plant cells. The cell wall is a rigid layer that is located outside the cell membrane and provides the cell with structural support and protection.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>4","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Animal cell are different from plant cell because animals have","images":[],"options":{"A":"Definite cell wall","B":"large vacoules","C":"centrioles","D":"chloroplasts"},"answer":"C","explanation":"Animal cells are different from plant cells in several ways, one of which is the presence of centrioles in animal cells. Centrioles are small, cylindrical organelles that are involved in the process of cell division, specifically in the formation of the spindle fibers that separate the chromosomes during mitosis. Plant cells do not have centrioles. Option 1 is incorrect because plant cells, not animal cells, have a definite cell wall. Option 2 is incorrect because both animal and plant cells can have large vacuoles. Option 4 is incorrect because chloroplasts are found in plant cells, not animal cells.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>5","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Which of the following depicts the external feautures of a rat as a mammal","images":[],"options":{"A":"long intestine","B":"Diaphragms","C":"milk and sweat production","D":"fur and whiskers"},"answer":"D","explanation":"The external features of a rat as a mammal are depicted by its fur and whiskers. Fur is a characteristic feature of mammals, providing them with insulation and protection. Whiskers, also known as vibrissae, are sensory hairs that provide mammals with a sense of touch, helping them navigate and detect changes in their environment. The other options like long intestine, diaphragms, and milk and sweat production are internal features or physiological processes, not external features.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>6","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Which of the following represent the correct sequence from the most simple, to the most complex of organisation","images":[],"options":{"A":"mitochondrin, muscles, alimentary canal, rabbit ,heart, neurone","B":"mitochodrion,neurone, muscle,heart, alimentary canal, rabbit","C":"alimentary canal, neurone, muscle, heart, rabbit,mitochondrion","D":"Rabbit, mitochondrin, heart, neuron , alimentary canal"},"answer":"B","explanation":"The level of organisation include   Cell\u2192Tissues\u2192organs \u2192system\u2192organisation  Hence  Mitochondria\u2192neuron \u2192muscle\u2192alimentary canal\u2192Rabbit.  Mitochondria\u2192 organelle  Neuron \u2192cell  Muscles \u2192tissue  heart \u2192organ  Alimentary canal \u2192system   Rabbit \u2192organisation","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>7","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Which of the following will cause wilting in plants?","images":[],"options":{"A":"humidity","B":"coldness","C":"adequates soil water","D":"excessive transpiration"},"answer":"D","explanation":"Wilting in plants is caused by excessive transpiration. Transpiration is the process by which water is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. When this process is excessive, it can lead to wilting as the plant loses more water than it can absorb from the soil, causing it to lose turgidity and droop.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>8","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the following definition best describes excretion?","images":[],"options":{"A":"liberation of energy from food","B":"release of face from the body","C":"breakdown of food molecules","D":"removal of waste product of metabolism"},"answer":"D","explanation":"Excretion is the process by which waste products of metabolism are eliminated from an organism. These waste products are by-products or excess substances that the body cannot use, and if they are allowed to accumulate, they would be harmful. Therefore, option 4 is the correct answer.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2002>9","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"In an experiment to study the rate of water loss in plant, leaves of a potted-plant were treated as follows  I. upper surface covered with vaseline  II. lower surface covered with vaseline  III. both surface  covered with vaseline  IV. none of the above    indicate in a descending order, rate of water loss from leaves","images":[],"options":{"A":"I, II,III and IV","B":"II,I,III and IV","C":"III, II, I and IV","D":"IV,I,II and III"},"answer":"D","explanation":"Water loss is greatest when none of the leaf surface is covered. This is the rate of water loss in descending order.  IV\u2192I\u2192II \u2192III","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>10","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"The following are method of measuring plant growth except","images":[],"options":{"A":"determination the fresh and dry weight of the plant","B":"counting the number of fruits produced","C":"measuring the increase in height of the shoot","D":"measuring the length and breadth of a leaf"},"answer":"B","explanation":"Plant growth is typically measured by parameters such as the increase in the plant's height, the fresh and dry weight of the plant, and the length and breadth of the leaves. These measurements provide information about the plant's overall growth and development. However, counting the number of fruits produced is not a direct method of measuring plant growth. While it can provide information about the plant's reproductive success, it does not directly measure the plant's growth or development. Therefore, the correct answer is option 2.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>11","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Which of the following will ease the friction between the ends of bones in a movables joint?","images":[],"options":{"A":"serum","B":"tissue","C":"blood plasma","D":"synovial fluid"},"answer":"D","explanation":"The correct answer is synovial fluid. In a movable joint, the ends of the bones are covered with a layer of cartilage. Between these layers of cartilage, there is a small amount of a thick, slippery liquid called synovial fluid. This fluid acts as a lubricant to reduce friction between the bones when they move. Therefore, synovial fluid eases the friction between the ends of bones in a movable joint.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>12","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Diffusion is most effective in living organism, when the surface area is","images":[],"options":{"A":"Large and thickness is also large","B":"small while the thickness is large","C":"large while the thickness is small","D":"the same as its thickness"},"answer":"C","explanation":"Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. It is most effective in living organisms when the surface area is large and the thickness is small. This is because a larger surface area allows for more molecules to diffuse at once, and a smaller thickness means the molecules have less distance to travel, making the process faster. Therefore, the correct answer is 'large while the thickness is small'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>13","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"The function of red blood cells is to","images":[],"options":{"A":"engulf invading bacteria","B":"aid in protein formation","C":"transport oxygen to the cell","D":"control blood glucose level"},"answer":"C","explanation":"Red blood cells, also known as erythrocytes, primarily transport oxygen from the lungs to the body's tissues. They do this by carrying a protein called hemoglobin, which binds to oxygen in the lungs and releases it in tissues that need it. The other options are incorrect because red blood cells do not engulf bacteria (that's the job of white blood cells), they do not aid in protein formation, and they do not control blood glucose levels (that's primarily the job of insulin and glucagon hormones).","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>14","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"which of the following is used to measure the rate of water uptake in plants?","images":[],"options":{"A":"potometer","B":"hydrometer","C":"hygometer","D":"aspirator"},"answer":"A","explanation":"A potometer is a device used for measuring the rate of water uptake of a leafy shoot. It is typically used to estimate transpiration rates. Transpiration is the process by which water is carried through plants from roots to small pores on the underside of leaves, where it changes to vapor and is released to the atmosphere. The other options, hydrometer, hygometer, and aspirator, are not used for this purpose. A hydrometer is used to measure the specific gravity (relative density) of liquids; a hygrometer is used to measure humidity in the air; and an aspirator is a device used to create a vacuum by flowing water through a narrow tube.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>15","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following does not occur during inhalation in mammals?","images":[],"options":{"A":"Rib cage is raised up","B":"Diaphragm contracts and becomes dome shaped","C":"inter-coastal muscles contracts","D":"volume of the thoraciccavity increases."},"answer":"B","explanation":"During inhalation in mammals, the diaphragm contracts and flattens, not becomes dome shaped. The contraction of the diaphragm increases the volume of the thoracic cavity, which decreases the pressure inside the lungs, allowing air to flow in. The other options are correct: the rib cage is raised up, the intercostal muscles contract, and the volume of the thoracic cavity increases.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>16","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The oxygen released during photosynthesis is obtained","images":[],"options":{"A":"From the catalytic splitting of carbon -dioxide in plant tissues","B":"from the breakdown of glucose molecules in cells","C":"During the photosyls is of water using energy trapped in chlorophyll","D":"by the excretion of excess oxygen in plant tissues"},"answer":"C","explanation":"During photosynthesis, plants take in carbon dioxide and water and convert them into glucose and oxygen. The oxygen that is released during this process is obtained from the photosynthesis of water using energy trapped in chlorophyll. This process is known as photolysis, where water molecules are broken down into hydrogen and oxygen in the presence of light. The oxygen is then released into the atmosphere.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>17","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"In which of the following process in mammals is liquid passed from blood capillaries to bowman's capsules?","images":[],"options":{"A":"filtration","B":"diffusion","C":"osmosis","D":"reabsorption"},"answer":"A","explanation":"In mammals, the process of passing liquid from blood capillaries to Bowman's capsules is called filtration. This process occurs in the kidneys, where the blood is filtered to remove waste products and excess substances. The Bowman's capsule is a part of the nephron, the functional unit of the kidney, where the filtration of blood takes place. The blood capillaries, also known as glomerulus, are surrounded by the Bowman's capsule, and the pressure in these capillaries forces water, ions, and small molecules into the Bowman's capsule. This process is not diffusion, osmosis, or reabsorption, but filtration.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>18","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Adrenalin is considered as hormone for ''fright  and flight'' because it's","images":[],"options":{"A":"controls the fluid content of the body","B":"is used in protein metabolism","C":"plays a role in the pH balance of the body fluid","D":"prepares the body for action"},"answer":"D","explanation":"Adrenalin, also known as epinephrine, is often referred to as the 'fight or flight' hormone because it prepares the body for action. It is released by the adrenal glands in response to stressful situations. When released, it increases heart rate, blood pressure, and blood glucose levels, thereby preparing the body for a sudden burst of energy needed for 'fight or flight'. None of the other options accurately describe the role of adrenalin.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>19","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the following organs in humans is responsible for the removal of excess water","images":[],"options":{"A":"the spleen","B":"the kidney","C":"large intestine","D":"small intestine"},"answer":"B","explanation":"The kidney is responsible for the removal of excess water in humans. It does this through the process of filtration, reabsorption, and secretion. Filtration is the process by which the kidneys filter out waste products, excess nutrients, and water from the blood. Reabsorption is the process by which the kidneys reabsorb useful substances back into the blood. Secretion is the process by which the kidneys secrete waste products and excess water into the urine, which is then excreted from the body. The other options, the spleen, large intestine, and small intestine, are not primarily involved in the removal of excess water.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>20","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"In humans, which of the following pairs of hormones correspond to male and female respectively","images":[],"options":{"A":"oestrogen and adrenaline","B":"progesterone and testostrone","C":"testosterone and oestrogen","D":"Adrenaline and progesterone"},"answer":"C","explanation":"In humans, the primary male sex hormone is testosterone, which is responsible for the development of male reproductive tissues and secondary sexual characteristics. On the other hand, oestrogen is the primary female sex hormone that regulates the menstrual cycle and is crucial for the development and maintenance of female secondary sexual characteristics. Therefore, the pair of hormones that correspond to male and female respectively are testosterone and oestrogen.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>21","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"if the cerebellum of a person is slightly damage , which of the following will be impaired?","images":[],"options":{"A":"vision","B":"walking","C":"breathing","D":"digestion"},"answer":"B","explanation":"The cerebellum is a part of the brain that is responsible for motor control. It does not initiate movement, but it contributes to coordination, precision, and accurate timing. It receives input from sensory systems and from other parts of the brain and spinal cord, and integrates these inputs to fine-tune motor activity. Hence, if the cerebellum of a person is slightly damaged, the person's walking ability will be impaired.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>22","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The structure of the ear that is responsible for balancing is the","images":[],"options":{"A":"semi-circular canal","B":"pinna","C":"auditory nerve","D":"fenstra ovalis"},"answer":"A","explanation":"The semi-circular canals are part of the inner ear and are responsible for maintaining balance. They are filled with a fluid that moves when your head changes position. This movement of fluid stimulates hair cells inside the canals, sending nerve impulses to the brain that interpret these movements as a change in position, thus helping to maintain balance.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>23","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"When a person moves from a darkroom into bright light, the pupil becomes","images":[],"options":{"A":"red","B":"larger","C":"white","D":"smaller"},"answer":"D","explanation":"When a person moves from a dark room into bright light, the pupil becomes smaller. This is due to the reflex action of the eye to control the amount of light entering the eye. In bright light, the iris contracts, reducing the size of the pupil to prevent damage to the retina from excessive light. This is known as the pupillary light reflex.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>24","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following is not example of entomophilous flower?","images":[],"options":{"A":"Hibiscus","B":"flambouyant","C":"guinea grass","D":"allamanda"},"answer":"C","explanation":"Entomophilous flowers are those that are pollinated by insects. Examples of entomophilous flowers include hibiscus, flambouyant, and allamanda. However, guinea grass is an anemophilous flower, meaning it is pollinated by wind, not insects. Therefore, guinea grass is not an example of an entomophilous flower.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>25","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"In flowering plants, fertilization would occur when","images":[],"options":{"A":"The pollen grows downwards penetrating the style","B":"a pollen grain is transferred to the stigma","C":"one of the nuclei inside the pollen tube fuses with the ovum","D":"the nucleus of pollen tube divide"},"answer":"C","explanation":"In flowering plants, fertilization occurs when one of the nuclei inside the pollen tube fuses with the ovum. This process is known as syngamy. The pollen grain lands on the stigma and grows a pollen tube down into the ovule. The pollen tube carries two sperm cells, one of which will fuse with the egg cell (ovum) to form a zygote (the first cell of the new plant), while the other fuses with two polar nuclei to form the endosperm, which serves as food storage within the seed. This is known as double fertilization, a process unique to flowering plants.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>26","subject":"Biology","year":"2002","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"After fertilization in the flowering plants, the zygote develops into the:","images":[],"options":{"A":"plumule","B":"radicle","C":"cotyledon","D":"embryo"},"answer":"D","explanation":"After fertilization in flowering plants, the zygote develops into the embryo. The embryo is the early stage of development of a multicellular organism. In the case of plants, the embryo later differentiates into different parts like the plumule, radicle, and cotyledon. Therefore, the correct answer is 'embryo'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>27","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following susbtances is contained in chloroplasts?","images":[],"options":{"A":"starch","B":"sugar","C":"Glycogen","D":"Dextrin"},"answer":"A","explanation":"Chloroplasts are the site of photosynthesis in plant cells, where light energy is converted into chemical energy in the form of glucose. During this process, glucose is stored in the form of starch granules within the chloroplasts. Therefore, the correct answer is starch. Glycogen and dextrin are forms of stored carbohydrates in animals and yeast respectively, not in chloroplasts. Sugar is a product of photosynthesis but it is not stored in the chloroplasts, it is transported out to other parts of the plant.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>28","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagram below is the root system of a leguminous plant.       The structure labelled II are","images":["data:image/png;base64,"],"options":{"A":"Groundnut seeds","B":"underground root nut","C":"root tubers","D":"root nodules"},"answer":"D","explanation":"II  is the root nodules. Root nodules are small, rounded growths on the roots of certain plants, such as legumes, which contain nitrogen-fixing bacteria. These bacteria help convert atmospheric nitrogen into a form that the plant can use, thereby enhancing soil fertility.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>29","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagram below is the root system of a leguminous plant.     The structure labelled II are associated with","images":["data:image/png;base64,"],"options":{"A":"storage is plant nutrients","B":"organic acids","C":"nitrogen-fixing bacteria","D":"putrefying microbes"},"answer":"C","explanation":"Root nodules, like the ones labeled II in the diagram, are formed on the roots of leguminous plants due to a symbiotic relationship with nitrogen-fixing bacteria, such as Rhizobium. These bacteria convert atmospheric nitrogen into ammonia, a form of nitrogen that plants can absorb and utilize for growth. This symbiosis is crucial for soil fertility and plant nutrition, particularly in nitrogen-poor soils.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>30","subject":"Biology","year":"2002","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"The deficiency disease that results from the lack of vitamin B due to frequent eating of rice is","images":[],"options":{"A":"rickets","B":"night blindness","C":"scurvy","D":"beri beri"},"answer":"D","explanation":"Beri beri is a disease caused by a deficiency of vitamin B1, also known as thiamine. This vitamin is found in foods such as whole grains, beans, peas, and nuts. Rice, especially white rice, is often deficient in thiamine because the outer layer of the grain, which contains most of the vitamin, is removed during processing. Therefore, people who eat a lot of rice, especially white rice, and not many other foods can develop beri beri.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>31","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"When a food substance gives a purple colour on the addition of sodium hydroxide and drop of copper sulphate, then the food substance is likely to contain","images":[],"options":{"A":"carbohydrate","B":"fat","C":"protein","D":"sugar"},"answer":"C","explanation":"The test described in the question is known as the Biuret test. It is a chemical test used for detecting the presence of peptide bonds, which are the bonds holding amino acids together in a protein. When a solution of sodium hydroxide and a drop of copper sulphate (the Biuret reagent) is added to a substance containing protein, it turns a purple color. Therefore, the food substance is likely to contain protein.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>32","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"In mammals digested food is absorbed in the","images":[],"options":{"A":"stomach","B":"ileum","C":"colon","D":"duodenum"},"answer":"B","explanation":"In mammals, the absorption of digested food primarily occurs in the ileum, which is a part of the small intestine. The small intestine is divided into three parts: the duodenum, jejunum, and ileum. The ileum is the longest part and it is where most of the absorption process happens. Nutrients such as sugars, amino acids, and fatty acids are absorbed here through the villi, tiny finger-like projections that increase the surface area for absorption. The other options are not primarily involved in the absorption of digested food. The stomach is involved in the breakdown of food, the colon absorbs water and electrolytes, and the duodenum, while part of the small intestine, is more involved in the continuation of digestion rather than absorption.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>33","subject":"Biology","year":"2002","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"using iodine solution, biuret test, benedict reagents and ethanol, respectively in testing for reducing sugar, which of the following trend of colour changes would be observed?","images":[],"options":{"A":"blue-black\u2192blue\u2192brown\u2192clear","B":"brown\u2192blue\u2192brick red\u2192 clear","C":"brown \u2192violet\u2192blue\u2192clear","D":"brown\u2192blue\u2192violet\u2192milky"},"answer":"C","explanation":"Considering the context of the tests described:  -\tIodine solution: Stays brown (no starch)Biuret test: Stays blue (if we assume no proteins, or could turn violet)  -\tBenedict's reagent: Stays blue (in absence of reducing sugars without heat)  -\tEthanol test: Stays clear (no lipids)  So the correct progression of colors would be:Brown (iodine) \u2192 blue (biuret) \u2192 blue (Benedict) \u2192 clear (ethanol)","marks":"1","difficulty":"3"},{"id":"objective>Biology>2002>34","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Ecology simply means the study of","images":[],"options":{"A":"the properties of a habitat","B":"interrelationship between organism and environment.","C":"several species of plant and animals","D":"interrelationship between plants and animals"},"answer":"B","explanation":"Ecology is the branch of biology that studies the interactions among organisms and their biophysical environment, which includes both biotic and abiotic components. It involves understanding the interrelationship between organisms and their environment.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>35","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : WATER CYCLE","question":"Which of the following processes remove water from the water cycle?","images":[],"options":{"A":"condensation","B":"perspiration","C":"photosynthesis","D":"transpiration"},"answer":"D","explanation":"Transpiration: is loss of water by evapouration from the aerial part of plant and it removes water from the cycle.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>36","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"The importance of practising crop-rotation in agriculture is to","images":[],"options":{"A":"control soil erosion","B":"maintain the fertility of the soil","C":"improve the nutritional value of crops","D":"ensure growth of cash crops"},"answer":"B","explanation":"Crop rotation is the practice of growing different types of crops in the same area, in sequenced seasons. It is done so that the soil of farms is not used for only one set of nutrients. It helps in reducing soil erosion and increases soil fertility and crop yield. Thus, the main importance of practising crop-rotation in agriculture is to maintain the fertility of the soil.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>37","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"In any chain, the first member must be a","images":[],"options":{"A":"carnivore","B":"herbivore","C":"zooplankton","D":"autotroph"},"answer":"D","explanation":"In any food chain, the first member must be an autotroph. Autotrophs are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis). They are the primary producers in a food chain, such as plants on land or algae in water. They are followed by herbivores (primary consumers), and then carnivores and omnivores (secondary and tertiary consumers).","marks":"1","difficulty":"1"},{"id":"objective>Biology>2002>38","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Which of the following measure is most likely to cause a damage to ecosystem in the control of pest and weeds?","images":[],"options":{"A":"use of the ladybird insects to feed on aphids.","B":"introduction of bacterium to kill larve of butterfly","C":"introduction the tilapia fish in ponds feed on mosquito larvae","D":"spraying insecticides to destroy cotton-stainers in a cotton field"},"answer":"D","explanation":"Spraying of insecticides can cause damage to the ecosystem , due to the fact that it can pollute the water bodies and also makes the soil toxic(When applied in excess)admist other effects.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2002>39","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"The total amount of energy entering a food chain is that which is present in the","images":[],"options":{"A":"consumer","B":"ecosystem","C":"producer","D":"decomposers"},"answer":"C","explanation":"The total amount of energy entering a food chain is that which is present in the producers. Producers, such as plants, are the first level in a food chain. They convert sunlight into energy through photosynthesis, which is then passed on to consumers and decomposers. Therefore, the total energy in a food chain originates from the producers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>40","subject":"Biology","year":"2002","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"which of the following terms ensures the survival of an organism in the environment?","images":[],"options":{"A":"Hibernation","B":"succession","C":"adaptation","D":"competition"},"answer":"C","explanation":"Adaptation is the process by which an organism becomes better suited to its environment. It is a key mechanism of evolution and helps to ensure the survival of an organism in its environment. Hibernation is a state of inactivity and metabolic depression in endotherms. Succession is the process by which a plant or animal community successively gives way to another until a stable climax is reached. Competition is a relationship between organisms that strive for the same resources in the same place.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>41","subject":"Biology","year":"2002","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"The concave shape of a birds wing during flight, ensures that a greater air pressure under wings will","images":[],"options":{"A":"counter the effect of gravity","B":"lift the bird so that it can remain airborne","C":"enable the pectoral muscles to contracts easily","D":"changes the direction of the flying bird"},"answer":"B","explanation":"The concave shape of a bird's wing during flight creates a pressure difference between the top and bottom of the wing. This pressure difference is what lifts the bird so that it can remain airborne. The greater air pressure under the wings doesn't counter the effect of gravity, enable the pectoral muscles to contract easily, or change the direction of the flying bird.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>42","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The prossession of breathing roots is a charateristics of plants growing in","images":[],"options":{"A":"mangrove swamp","B":"coastal savanna","C":"guniea savanna","D":"shrub biome"},"answer":"A","explanation":"Breathing roots, also known as pneumatophores, are a type of root that protrudes above the ground in some plant species. They are a characteristic feature of many swamp and marsh plants, including mangroves. These roots emerge from the water or ground to access the air, which is low in the waterlogged soil, to facilitate respiration. Therefore, the correct answer is 'mangrove swamp'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>43","subject":"Biology","year":"2002","type":"Objective","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"The numbers in population would rise if there was an increase in the","images":[],"options":{"A":"spread of disease","B":"number of deaths","C":"number of predators","D":"amount of food available"},"answer":"D","explanation":"The number in a population would rise if there was an increase in the amount of food available. This is because food is a basic necessity for survival and reproduction. If there is more food available, it means that more individuals in the population can be supported, leading to an increase in the population size.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>44","subject":"Biology","year":"2002","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"measles in infants can be prevented by","images":[],"options":{"A":"sleeping under mosquito nets","B":"providing clean water","C":"taking anti-malaria tablets","D":"vaccinating young children"},"answer":"D","explanation":"Measles is a highly contagious viral disease that can be prevented through vaccination. The measles vaccine is typically administered to children as part of their routine immunization schedule. Therefore, the correct answer is 'vaccinating young children'. The other options are incorrect as they are not related to the prevention of measles. Sleeping under mosquito nets and taking anti-malaria tablets are measures to prevent malaria, not measles. Providing clean water can prevent diseases caused by water contamination, but not measles.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>45","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"micro-organism are important in recycling nutrient because","images":[],"options":{"A":"they are capable of multiplying quickly","B":"they are beaten by a organism","C":"they break down dead organic materials","D":"many of them ae parasites"},"answer":"C","explanation":"Micro organism break down dead organic material, this process aids nutrient recycling i.ebiodegradation of materials is impoertant for nutrient recycling","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>46","subject":"Biology","year":"2002","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"A vegetable farmer will benefit from a cattle rearer if","images":[],"options":{"A":"the faecal remains of the cattle are made available to the farmer","B":"the farmer makes available fresh green vegetables for consumption by the cattle daily","C":"the farmer provides shelter for the cattle and the cattle rearer","D":"the cattle reare makes available meat available meat to the farmer daily"},"answer":"A","explanation":"The faecal remains of the cattle can be used as manure by the vegetable farmer. This manure is rich in nutrients and can improve the fertility of the soil, thereby benefiting the farmer by increasing the yield of his crops. This is a concept in agriculture known as integrated farming system where the waste product of one system becomes the input for another system.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>47","subject":"Biology","year":"2002","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Wildlife conservation is enhanced by","images":[],"options":{"A":"enacting laws to encourage poaching","B":"discouraging elimination of endangered species","C":"encouraging creation of statellite hunting unit","D":"suppressing the activities of wildlife conservation agencies"},"answer":"B","explanation":"Wildlife conservation is enhanced by discouraging the elimination of endangered species. This is because the goal of wildlife conservation is to ensure that nature will be around for future generations to enjoy and to recognize the importance of wildlife and wilderness for humans and other species alike. Therefore, discouraging the elimination of endangered species is a direct way to enhance wildlife conservation. The other options do not contribute to wildlife conservation. For instance, enacting laws to encourage poaching would actually harm wildlife conservation, not enhance it. Similarly, suppressing the activities of wildlife conservation agencies would also be detrimental to wildlife conservation efforts.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>48","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of these statement is true about fingerprint patterns?","images":[],"options":{"A":"consistence for lifetime","B":"may be exactly the same for two individuals","C":"prominent only at puberty","D":"correlates with the individual blood group"},"answer":"A","explanation":"Fingerprints are unique to each individual and remain consistent throughout a person's lifetime. They are formed during the fetal development stage and do not change as we grow. This is because the basic structure of a fingerprint is determined by the dermal papillae, which develops before birth and remains unchanged throughout life. Therefore, the statement 'consistence for lifetime' is true. The other options are incorrect. Fingerprints are not exactly the same for two individuals, they do not become prominent only at puberty, and they do not correlate with an individual's blood group.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>49","subject":"Biology","year":"2002","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"some species of animals and plants are considered as endangered because","images":[],"options":{"A":"they are found in large number in most habitat","B":"they are harmful to their natural habitats","C":"their population have become so small that they may soon die out","D":"they should be killed or only kept in cages"},"answer":"C","explanation":"Endangered species are those species of animals or plants that are considered at risk of extinction. This is often due to a drastic decline in their population numbers, usually as a result of factors like habitat loss, climate change, or overexploitation. Therefore, the statement 'their population have become so small that they may soon die out' is the correct answer. The other options are incorrect because endangered species are not necessarily harmful to their habitats, nor are they found in large numbers in most habitats. Also, the idea of killing them or keeping them only in cages does not relate to their endangered status.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>50","subject":"Biology","year":"2002","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Which of the following is continous variation,in human population ?","images":[],"options":{"A":"sex","B":"Rh factor","C":"height","D":"Downs syndrome"},"answer":"C","explanation":"Continuous variation, in biology, refers to a genetic phenomenon where individuals in a population vary in small ways from each other due to the effect of multiple genes. This variation is often represented on a spectrum or continuum rather than in discrete categories. Height in humans is a classic example of continuous variation because it is determined by the cumulative effect of many genes and environmental factors, and individuals can be any height within a certain range, not just short, medium, or tall. Therefore, the correct answer is 'height'. The other options, 'sex', 'Rh factor', and 'Downs syndrome', are examples of discontinuous variation where individuals fall into a few distinct categories.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>51","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of the following statement about blood groups in human is not correct?","images":[],"options":{"A":"siblings may not belong to the same blood group","B":"there are four possible blood groups","C":"people with blood group O can recieve blood from all other groups","D":"people with blood group AB are universal recipient"},"answer":"C","explanation":"People with blood group O cannot receive blood from all other groups. This statement is incorrect because people with blood group O are universal donors, not universal recipients. They can donate blood to any group, but they can only receive blood from their own group (O). The concept behind this is related to the presence or absence of antigens and antibodies in the blood. Blood group O has no antigens but both A and B antibodies, therefore, it can only receive blood from its own group to avoid agglutination (clumping of red blood cells due to antibody-antigen reaction).","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>52","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"When mendel crossed round seeds with winkled seeds of pea plant, what was the ratio of wrinkled seeds to round seeds in F2 plants?","images":[],"options":{"A":"3:1","B":"2:1","C":"1:3","D":"1:2"},"answer":"C","explanation":"The ratio of wrinkled seeds to round seeds in F2 plants 1:3","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>53","subject":"Biology","year":"2002","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Which of the following is not a morphological variation in human beings?","images":[],"options":{"A":"size","B":"blood groups","C":"colour","D":"fingerprints"},"answer":"B","explanation":"Morphological variations refer to the observable physical differences among individuals of a species. These can include variations in size, color, and fingerprints among human beings. However, blood groups are not a morphological variation. Blood groups are a type of genetic variation, determined by the presence or absence of certain antigens on the surface of red blood cells. Therefore, the correct answer is 'blood groups'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>54","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"The name given to a sudden change in a gene or chromosome that can be passed on the offspring is","images":[],"options":{"A":"inheritance","B":"linkage","C":"alleles","D":"mutation"},"answer":"D","explanation":"A sudden change in a gene or chromosome that can be passed on to the offspring is called a mutation. Mutations can occur randomly or due to exposure to specific environmental factors. They can lead to new traits in individuals, and if beneficial, these traits can be passed on to future generations, contributing to evolution. Inheritance refers to the passing of traits from parents to offspring, linkage refers to the tendency of genes that are close together on a chromosome to be inherited together, and alleles are different forms of a gene.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>55","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS","question":"in humans, sex is determined by","images":[],"options":{"A":"two homologous chromosomes","B":"a dominant gene foe maleness present in a male","C":"two similar sex chromosomes in the male and dissimiliar in the female","D":"the difference in the nature of x and Y chromosomes in the males"},"answer":"D","explanation":"In humans, sex is determined by the difference in the nature of X and Y chromosomes in males. Females have two of the same kind of sex chromosome (XX), while males have two distinct sex chromosomes (XY). The presence of the Y chromosome determines maleness because it carries the SRY gene, which triggers the development of male characteristics. The X chromosome carries genes related to both male and female sexual development. Therefore, the correct answer is 'the difference in the nature of X and Y chromosomes in the males'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>56","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"A male with heterozygous genotype for blood group B marries  a woman with heterozygous, A, what percentage (%) of their children would be universal donor?","images":[],"options":{"A":"50%","B":"25%","C":"15%","D":"10%"},"answer":"B","explanation":"Universal donor is blood group O. The man and woman are heterozygous B and A repectively(AO and BO) and have 25% chance of having a child who is a universal donor","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>57","subject":"Biology","year":"2002","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"The genes affecting the same trait and are located at the same position on the homologous chromosomes are called","images":[],"options":{"A":"autosomes","B":"alleles","C":"loci","D":"chromatids"},"answer":"B","explanation":"The genes affecting the same trait and are located at the same position on the homologous chromosomes are called alleles. Alleles are different forms of the same gene. They are located at the same locus (position) on homologous chromosomes. Autosomes are non-sex chromosomes. Loci is the plural form of locus, which refers to the specific location of a gene or DNA sequence on a chromosome. Chromatids are the two identical halves of a duplicated chromosome.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>58","subject":"Biology","year":"2002","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following is an adaptation by plants to reduce the rate of water loss in a dry habitat possession of","images":[],"options":{"A":"a few sunken stomata on a lower epidermis only","B":"long leaf tendrils","C":"leaves with serrated edges","D":"strong tap roots"},"answer":"A","explanation":"Stomata are tiny openings or pores in plant tissue that allow for gas exchange. In dry habitats, plants adapt by having fewer stomata that are sunken into the lower epidermis of the leaves. This reduces the surface area exposed to the air, thereby reducing the rate of water loss through transpiration. The other options do not directly relate to the reduction of water loss. Long leaf tendrils are for climbing or support, leaves with serrated edges can help deter herbivores, and strong tap roots are for anchoring the plant and reaching deep water sources, but they do not reduce the rate of water loss.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>59","subject":"Biology","year":"2002","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"The following are social insects excepts","images":[],"options":{"A":"wasps","B":"termites","C":"bees","D":"cotton stainer"},"answer":"D","explanation":"Social insects are those that live in colonies or have some sort of organized social structure. Examples of social insects include bees, ants, wasps, and termites. These insects have a division of labor, with different individuals performing different roles within the colony. The cotton stainer, on the other hand, is not a social insect. It does not live in colonies or have an organized social structure. Therefore, the correct answer is 'cotton stainer'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2002>60","subject":"Biology","year":"2002","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Which of the following can be considered as a direct evidence of evolution?","images":[],"options":{"A":"classification","B":"comparative anatomy","C":"comparative embryology","D":"fossil record"},"answer":"D","explanation":"The fossil record is considered a direct evidence of evolution. Fossils are the preserved remains or traces of animals, plants, and other organisms from the past. Over time, species have changed and developed, becoming more complex. This change and development can be seen in the fossil record, making it a direct evidence of evolution. Classification, comparative anatomy, and comparative embryology are all indirect evidences of evolution. They provide support for the theory of evolution but do not show the actual process of evolution over time.","marks":"1","difficulty":"2"}];